sysauto_script.script:
(function() {
    // Find appointments scheduled for tomorrow
    var tomorrow = new GlideDateTime();
    tomorrow.addDaysUTC(1);
    var tomorrowDate = tomorrow.getDate().getValue();

    var gr = new GlideRecord('x_1920732_lifeli_0_appointment');
    gr.addQuery('appointment_status', 'scheduled');
    gr.addQuery('appointment_date', '>=', tomorrowDate + ' 00:00:00');
    gr.addQuery('appointment_date', '<=', tomorrowDate + ' 23:59:59');
    gr.query();

    var count = 0;
    while (gr.next()) {
        gs.eventQueue('x_1920732_lifeli_0.appt.reminder', gr, gr.getValue('donor'), gr.getValue('blood_bank'));
        count++;
    }
    gs.info('LifeLink: Appointment Reminder Scheduler sent ' + count + ' reminders for ' + tomorrowDate);
})();
